    /* Resource card descriptions (288) */
    'cd_000': 'Preisgekrönte App zur frühen Lesefähigkeit — Buchstaben, Lautlehre, Geschichten und Schreiben, alles kostenlos und werbefrei.',
    'cd_001': 'Bekannte Schauspieler lesen Kinderbücher vor — wunderschöne Videos, die frühes Hören und Lesen fördern.',
    'cd_002': '40.000+ digitale Bücher, Hörbücher und Mitlese-Geschichten — kostenlos für Lehrkräfte während der Schulzeit.',
    'cd_003': 'Tausende hochwertige Lesetexte mit Verständnisfragen — kostenlos für K-12.',
    'cd_004': 'Kostenlose digitale Bibliothek mit 2.000+ literarischen und Sachtexten samt geführtem Lesen, Diskussion und Bewertung.',
    'cd_005': 'Adaptive Grammatik- und Schreibübungen, die sich an den Interessen jedes Schülers orientieren — kostenlose Basisversion.',
    'cd_006': 'Strukturierte Englisch-Lektionen, Videos und Quizze für Primar- und Sekundarstufe, kostenlos und werbefrei.',
    'cd_007': 'Adaptiver Wortschatz-Trainer — erkennt, was du kennst, und übt gezielt deine Lücken; ideal zur SAT-Vorbereitung.',
    'cd_008': 'Schüler werden zu Autoren — eigene digitale Bücher direkt im Browser schreiben, illustrieren und veröffentlichen.',
    'cd_009': 'KI-Schreibassistent, der Grammatik, Rechtschreibung und Verständlichkeit prüft — der Gratis-Tarif reicht für Schüler völlig aus.',
    'cd_010': '70.000+ kostenlose, gemeinfreie E-Books — klassische Literatur, Lyrik und Sachbücher, völlig kostenlos zum Download.',
    'cd_011': 'Kostenlose interaktive Schreib- und Grammatikübungen — sofortiges Feedback zu Satzbau und Korrekturlesen.',
    'cd_012': 'Lautlehre, Lieder und frühe Leseaktivitäten — eine seit Langem beliebte kostenlose Seite für Leseanfänger.',
    'cd_013': 'Kostenlose E-Book-Bibliothek von Oxford — Hunderte gestufte Lesebücher mit Audio-Erzählung.',
    'cd_014': 'Preisgekröntes Lautlehre-Abenteuer — kostenlos im Web, weltweit von Schulen genutzt.',
    'cd_015': 'Die weltweit beliebteste Sprach-App — gamifizierter Wortschatz, Grammatik und Lesen, kostenlos mit Werbung.',
    'cd_016': 'Kostenlose Lese- und Alphabet-Spiele mit beliebten PBS-Charakteren.',
    'cd_017': 'Tägliches Wonder of the Day — kurze Sachtexte, die Neugier und Wortschatz fördern.',
    'cd_018': 'Schreibcoach im Browser, der lange Sätze und Passivkonstruktionen markiert — schärft den Stil.',
